// Add Auto-Attack to all selected actors, but skip ones that already have it
const selectedTokens = canvas.tokens.controlled;

if (selectedTokens.length === 0) {
  ui.notifications.warn("No tokens selected.");
  return;
}

// Set your Auto-Attack UUID here
const traitUUID = "Item.j6BaZs9wW871CgFj";

const traitItem = await fromUuid(traitUUID);
if (!traitItem) {
  ui.notifications.error("Trait item not found with the provided UUID.");
  return;
}

let addedCount = 0;
let skippedCount = 0;
const results = [];

for (const t of selectedTokens) {
  const actor = t.actor;
  if (!actor) continue;

  // Check if this actor already has an item created from the UUID,
  // or (fallback) an item with the same name.
  const alreadyHas = actor.items.some(i =>
    i.getFlag?.("core", "sourceId") === traitUUID ||
    i.name === traitItem.name
  );

  if (alreadyHas) {
    skippedCount++;
    results.push(`Skipped (already has): ${actor.name}`);
    continue;
  }

  await actor.createEmbeddedDocuments("Item", [traitItem.toObject()]);
  addedCount++;
  results.push(`Added to: ${actor.name}`);
}

const total = selectedTokens.length;
ui.notifications.info(
  `Processed ${total} token(s): Added ${addedCount}, Skipped ${skippedCount}.`
);
console.log(results.join("\n"));
